# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions, account_balances):
    """
    Process financial transactions and update account balances.
    
    Args:
        transactions (list): List of transaction dictionaries with 'account_id', 'amount', and 'type' keys
        account_balances (dict): Dictionary mapping account_ids to current balances
    
    Returns:
        dict: Updated account balances
    """
    # Initialize balances if not present
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        transaction_type = transaction['type']
        
        # Ensure account exists in balances
        if account_id not in account_balances:
            account_balances[account_id] = 0
        
        # Process transaction based on type
        if transaction_type == 'credit':
            account_balances[account_id] += amount
        elif transaction_type == 'debit':
            account_balances[account_id] -= amount
        elif transaction_type == 'transfer':
            # For transfer, we need to handle both debit and credit
            # Assuming transaction has 'to_account_id' and 'from_account_id'
            if 'to_account_id' in transaction:
                account_balances[transaction['to_account_id']] += amount
            if 'from_account_id' in transaction:
                account_balances[transaction['from_account_id']] -= amount
    
    return account_balances

